package main

import (
	"context"
	"fmt"
	"log"
	"sync"
	"time"
)

// Telemetry 遥测记录结构
type Telemetry struct {
	ID        string
	Timestamp time.Time
	Metric    string
	Value     float64
}

// WorkerPool 工作池结构
type WorkerPool struct {
	numWorkers int
	taskQueue  chan []Telemetry
	ctx        context.Context
	cancel     context.CancelFunc
	wg         sync.WaitGroup
}

// NewWorkerPool 创建工作池
func NewWorkerPool(numWorkers int) *WorkerPool {
	ctx, cancel := context.WithCancel(context.Background())
	return &WorkerPool{
		numWorkers: numWorkers,
		taskQueue:  make(chan []Telemetry, 1000),
		ctx:        ctx,
		cancel:     cancel,
	}
}

// Start 启动工作池
func (wp *WorkerPool) Start() {
	for i := 0; i < wp.numWorkers; i++ {
		wp.wg.Add(1)
		go wp.worker(i)
	}
}

// worker 工作协程
func (wp *WorkerPool) worker(id int) {
	defer wp.wg.Done()
	for {
		select {
		case <-wp.ctx.Done():
			return
		case records := <-wp.taskQueue:
			wp.processWithRetry(records)
		}
	}
}

// processWithRetry 带重试的处理逻辑
func (wp *WorkerPool) processWithRetry(records []Telemetry) {
	maxRetries := 3
	var lastErr error

	for attempt := 1; attempt <= maxRetries; attempt++ {
		if err := wp.writeRecords(records); err != nil {
			lastErr = err
			log.Printf("[Attempt %d/%d] 写入失败: %v, 重试中...", attempt, maxRetries, err)
			if attempt < maxRetries {
				time.Sleep(time.Duration(attempt*100) * time.Millisecond)
			}
		} else {
			log.Printf("成功写入 %d 条遥测记录", len(records))
			return
		}
	}

	log.Printf("[ERROR] 写入失败，已重试 %d 次: %v", maxRetries, lastErr)
}

// writeRecords 模拟写入操作
func (wp *WorkerPool) writeRecords(records []Telemetry) error {
	// 模拟写入延迟
	time.Sleep(10 * time.Millisecond)

	// 模拟随机失败（10% 概率）
	if len(records)%10 == 0 {
		return fmt.Errorf("模拟写入失败")
	}

	return nil
}

// HandleBatch 处理批量遥测记录
func (wp *WorkerPool) HandleBatch(records []Telemetry) {
	if len(records) == 0 {
		return
	}

	select {
	case wp.taskQueue <- records:
		log.Printf("已提交 %d 条记录到任务队列", len(records))
	case <-wp.ctx.Done():
		log.Println("工作池已关闭，无法提交任务")
	}
}

// Shutdown 关闭工作池
func (wp *WorkerPool) Shutdown() {
	wp.cancel()
	close(wp.taskQueue)
	wp.wg.Wait()
}

func main() {
	pool := NewWorkerPool(4)
	pool.Start()
	defer pool.Shutdown()

	records := make([]Telemetry, 100)
	for i := 0; i < 100; i++ {
		records[i] = Telemetry{
			ID:        fmt.Sprintf("rec-%d", i),
			Timestamp: time.Now(),
			Metric:    "cpu_usage",
			Value:     float64(i),
		}
	}

	pool.HandleBatch(records)
	time.Sleep(100 * time.Millisecond)
}
