import java.util.concurrent.ConcurrentHashMap;

// 统一响应对象
class Response<T> {
    private int code;
    private String message;
    private T data;

    public Response(int code, String message, T data) {
        this.code = code;
        this.message = message;
        this.data = data;
    }

    public static <T> Response<T> success(T data) {
        return new Response<>(200, "success", data);
    }

    public static <T> Response<T> error(int code, String message) {
        return new Response<>(code, message, null);
    }

    public int getCode() { return code; }
    public String getMessage() { return message; }
    public T getData() { return data; }
}

// 请求 DTO
class CreateOrderRequest {
    private String requestId;
    private String userId;
    private String stationId;
    private double amount;

    public CreateOrderRequest(String requestId, String userId, String stationId, double amount) {
        this.requestId = requestId;
        this.userId = userId;
        this.stationId = stationId;
        this.amount = amount;
    }

    public String getRequestId() { return requestId; }
    public String getUserId() { return userId; }
    public String getStationId() { return stationId; }
    public double getAmount() { return amount; }
}

// 响应 DTO
class OrderResponse {
    private String orderId;
    private String requestId;
    private String status;

    public OrderResponse(String orderId, String requestId, String status) {
        this.orderId = orderId;
        this.requestId = requestId;
        this.status = status;
    }

    public String getOrderId() { return orderId; }
    public String getRequestId() { return requestId; }
    public String getStatus() { return status; }
}

// Service 层
class OrderService {
    private final ConcurrentHashMap<String, OrderResponse> processedRequests = new ConcurrentHashMap<>();

    public Response<OrderResponse> createOrder(CreateOrderRequest request) {
        String requestId = request.getRequestId();

        synchronized (processedRequests) {
            if (processedRequests.containsKey(requestId)) {
                return Response.error(409, "重复请求");
            }

            String orderId = "ORD" + System.currentTimeMillis();
            OrderResponse orderResponse = new OrderResponse(orderId, requestId, "CREATED");
            processedRequests.put(requestId, orderResponse);

            return Response.success(orderResponse);
        }
    }
}

// Controller 层
class OrderController {
    private final OrderService orderService = new OrderService();

    public Response<OrderResponse> createOrder(CreateOrderRequest request) {
        return orderService.createOrder(request);
    }
}
